--
-- Table structure for table `regist_level`
--

DROP TABLE IF EXISTS `regist_level`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `regist_level` (
  `id` int NOT NULL AUTO_INCREMENT,
  `regist_name` varchar(50) NOT NULL COMMENT '级别名称',
  `sequence_no` varchar(20) DEFAULT NULL COMMENT '序号',
  `regist_fee` decimal(10,2) DEFAULT '0.00' COMMENT '挂号费',
  `regist_quota` int DEFAULT '0' COMMENT '号额',
  `deleted` tinyint NOT NULL DEFAULT '0' COMMENT '逻辑删除: 0未删除, 1已删除',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COMMENT='挂号级别表';
/*!40101 SET character_set_client = @saved_cs_client */;

